                        var colName   = reader.GetString(0);
                        var typeName  = reader.GetString(1);
                        var maxLength = reader.GetInt16(2);
                        var precision = reader.GetByte(3);
                        var scale     = reader.GetByte(4);
                        var nullable  = reader.GetBoolean(5);

